#include<bits/stdc++.h>
using namespace std;
const int NM = 2e5+5;
struct line{int u,v;long long w;}ln[NM];
int n,m,k,sza[NM],szb[NM],f[NM];
long long ans;
bool cmp(line ln1,line ln2){return ln1.w<ln2.w;}
int Find(int x){return f[x]==x?x:f[x]=Find(f[x]);}
int main(){
    cin>>n>>m>>k;
    for(int i=1;i<=m;i++)
        cin>>ln[i].u>>ln[i].v>>ln[i].w;
    for(int i=1;i<=k;i++){int x;cin>>x;sza[x]++;}
    for(int i=1;i<=k;i++){int x;cin>>x;szb[x]++;}
    for(int i=1;i<=n;i++)f[i]=i;
    sort(ln+1,ln+m+1,cmp);
    for(int i=1;i<=m;i++){
        int x=ln[i].u,y=ln[i].v,z=ln[i].w;
        int fx=Find(x),fy=Find(y);
        if(fx==fy)continue;
        long long cnt=0;
        if(sza[fx]>=szb[fy])cnt+=szb[fy],sza[fx]-=szb[fy],szb[fy]=0;
        else cnt+=sza[fx],szb[fy]-=sza[fx],sza[fx]=0;
        if(szb[fx]>=sza[fy])cnt+=sza[fy],szb[fx]-=sza[fy],sza[fy]=0;
        else cnt+=szb[fx],sza[fy]-=szb[fx],szb[fx]=0;
        ans+=cnt*z;f[fy]=fx,sza[fx]+=sza[fy],szb[fx]+=szb[fy];
    }
    cout<<ans;
    return 0;
}
